#!/system/bin/sh
# AETHER SHOT - Self-Extracting Physics AI Engine
# No dependencies required - pure Python
# Fix for Termux: uses HOME instead of /tmp

# Detect environment
if [ -d "${PREFIX:-/data/data/com.termux/files/usr}" ]; then
    TMPDIR="$HOME/.cache/aether_shot"
elif [ -d "$HOME" ]; then
    TMPDIR="$HOME/.cache/aether_shot"
else
    TMPDIR="/data/local/tmp/.aether_shot"
fi

mkdir -p "$TMPDIR" 2>/dev/null || {
    echo 'Cannot create temp directory. Check permissions.'
    echo 'Try: mkdir -p $HOME/.cache'
    exit 1
}

DIR="$TMPDIR/$(date +%s)"
mkdir -p "$DIR/aether_shot"
cd "$DIR"
echo "" | base64 -d > aether_shot/physics_mirror.py
echo "" | base64 -d > aether_shot/ensemble.py
echo "" | base64 -d > aether_shot/session.py
echo "" | base64 -d > aether_shot/adaptive.py
echo "" | base64 -d > aether_shot/serverless.py
echo "" | base64 -d > aether_shot/__init__.py

cd aether_shot

PYTHON_CMD=""
for cmd in python3 python python3.11 python3.10; do
    if command -v "$cmd" >/dev/null 2>&1; then
        PYTHON_CMD="$cmd"
        break
    fi
done

if [ -z "$PYTHON_CMD" ]; then
    echo 'Python not found. Install: pkg install python'
    cd /
    rm -rf "$DIR"
    exit 1
fi

"$PYTHON_CMD" __init__.py
EXIT_CODE=$?
cd /
rm -rf "$DIR"
exit $EXIT_CODE
